//SB, DLT, 10/04/2026
/// <summary>
/// Method calls the SalesAgreementHeaderEntity helper class for the ds - SalesAgreementHeader
/// </summary>
public boolean insertEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret;

    ret = next insertEntityDataSource(_entityCtx, _dataSourceCtx);

    if (ret && _dataSourceCtx.name() == dataEntityDataSourceStr(SalesAgreementHeaderEntity, SalesAgreementHeader) && ETGCanadaParameters::find().EnableIntercompanyB2BSync)
    {
        SalesAgreementHeaderEntity SalesAgreementHeaderEntity  = _entityCtx.getEntityRecord();
        SalesAgreementHeader     SalesAgreementHeader     = _dataSourceCtx.getBuffer();

        ETGSalesAgreementHeaderEntityHelper helper = ETGSalesAgreementHeaderEntityHelper::construct(SalesAgreementHeader);
        helper.run();
    }
    return ret;
}
